mapper.select:
SELECT t1.id as taskId, t1.task_code taskCode, t1.required_completion_time requestDate, t1.end_detection_time finishDate, t2.report_code reportCode, t2.state state, t1.entrustment_id FROM test_task AS t1 LEFT JOIN test_report_record AS t2 ON t2.entrustment_id = t1.entrustment_id WHERE 1=1
and t1.dept_id = #{deptId}
and t1.required_completion_time >= #{requestDate}
and t1.end_detection_time >= #{finishDate}
and t1.start_detection_time >= #{startDate}
and t1.end_detection_time <= #{stopDate}
ORDER BY t1.task_code DESC

SELECT t2.NAME deptName, t2.CODE code, t3.NAME name, t3.user_id userId FROM test_technicist AS t1 LEFT JOIN test_team AS t2 ON t1.team_id = t2.id LEFT JOIN sys_user AS t3 ON t3.user_id = t1.user_id WHERE 1=1
and t2.id in
#{id}

SELECT id, entrustment_no, entrust_company, entrust_people, project_name, business_acceptor, acceptance_date, state FROM test_entrusted_info where 1=1
and acceptance_date >= #{startDate}
and acceptance_date <= #{stopDate}

SELECT id, inspector inspector, reviewer reviewer FROM test_task where 1=1
and start_detection_time >= #{startDate}
and end_detection_time <= #{stopDate}

SELECT id, inspector inspector, reviewer reviewer FROM test_task where 1=1
and review_time >= #{startDate}
and review_time <= #{stopDate}

SELECT id, verifyer_id verifyerId, issuer_id issuerId, sealer sealer FROM test_report_record where 1=1
and seal_time >= #{startDate}
and seal_time <= #{stopDate}

SELECT id, verifyer_id verifyerId, issuer_id issuerId, sealer sealer FROM test_report_record where 1=1
and verifyer_time >= #{startDate}
and verifyer_time <= #{stopDate}

SELECT id, verifyer_id verifyerId, issuer_id issuerId, sealer sealer FROM test_report_record where 1=1
and issuer_time >= #{startDate}
and issuer_time <= #{stopDate}

SELECT t1.id as task_id, t1.task_code task_code, t1.required_completion_time requestDate, t1.review_time finishDate, t2.report_code, t1.state, t1.task_price cost, t2.type, t1.entrustment_id, t4.id sample_id, t4.alias_name , t5.id as itemId, t5.times, t5.unit_price, t5.check_item_name, t5.state item_state, t5.task_id item_task_id, t6.discount FROM test_task AS t1 LEFT JOIN test_entrusted_sample_details_rel AS t3 ON t3.entrustment_id = t1.entrustment_id LEFT JOIN test_sample AS t4 ON t3.sample_id = t4.id LEFT JOIN test_entrusted_sample_checkitem_rel AS t5 ON t5.sample_id = t4.id LEFT JOIN test_entrusted_info as t6 ON t1.entrustment_id = t6.id LEFT JOIN test_report_record AS t2 ON t2.entrustment_id = t1.entrustment_id
and t1.id >0
and t1.dept_id in
#{id}
and t1.required_completion_time <= #{requestDate}
and t1.review_time <= #{finishDate}
and t1.start_detection_time >= #{startDate}
and t1.end_detection_time <= #{stopDate}
ORDER BY t1.task_code DESC

SELECT id as task_id,entrustment_id FROM test_task

    and id >0
    
        and dept_id in
        
            #{id}
        
    
    
        and required_completion_time  <=   #{requestDate}
    
    
        and review_time  <=   #{finishDate}
    
    
        and start_detection_time  >=   #{startDate}
    
    
        and end_detection_time  <=   #{stopDate}
    

ORDER BY task_code DESC

SELECT t1.teamId, t1.teamName, t1.teamCode, t1.taskPrice, IFNULL( t2.actualReportPrice, 0 ) actualReportPrice, IFNULL( t2.systemReportPrice, 0 ) systemReportPrice FROM ( SELECT t3.id teamId, t3.NAME teamName, t3.CODE teamCode, t3.pid, SUM( IFNULL( t2.discount, 1 ) * IFNULL( t4.unit_price, 0 ) *IFNULL( t4.times, 0 ) ) taskPrice FROM test_task t1 LEFT JOIN test_entrusted_info t2 ON t1.entrustment_id = t2.id LEFT JOIN test_team t3 ON t1.dept_id = t3.id LEFT JOIN test_entrusted_sample_checkitem_rel t4 ON t1.id = t4.task_id
t1.review_time is not null
and t3.NAME = #{taskSource}
and t3.pid = #{teamId}
and DATE_FORMAT(t1.review_time, '%Y-%m-%d')>= DATE_FORMAT(#{beginDate}, '%Y-%m-%d')
and DATE_FORMAT(t1.review_time, '%Y-%m-%d')<= DATE_FORMAT(#{endDate}, '%Y-%m-%d')
GROUP BY t3.NAME, t3.CODE, t3.id ) t1 LEFT JOIN ( SELECT t3.id teamId, t3.NAME teamName, SUM( IFNULL( t2.discount, 1 ) * IFNULL( t5.unit_price, 0 ) * IFNULL( t5.times, 0 ) ) actualReportPrice, SUM( IFNULL( t5.unit_price, 0 )) systemReportPrice FROM test_task t1 LEFT JOIN test_entrusted_info t2 ON t1.entrustment_id = t2.id LEFT JOIN test_team t3 ON t1.dept_id = t3.id LEFT JOIN test_report_record t4 ON t2.id = t4.entrustment_id LEFT JOIN test_entrusted_sample_checkitem_rel t5 ON t1.id = t5.task_id
and t3.NAME = #{taskSource}
and t3.pid = #{teamId}
and DATE_FORMAT(t4.issuer_time, '%Y-%m-%d')>= DATE_FORMAT(#{beginDate}, '%Y-%m-%d')
and DATE_FORMAT(t4.issuer_time, '%Y-%m-%d')<= DATE_FORMAT(#{endDate}, '%Y-%m-%d')
GROUP BY t3.NAME, t3.id ) t2 ON t1.teamId = t2.teamId

SELECT t3.id teamId, t3.name teamName, IFNULL(t3.code,'——') teamCode, IFNULL(t1.taskPrice,0) taskPrice, IFNULL( t2.actualReportPrice, 0 ) actualReportPrice, IFNULL( t2.systemReportPrice, 0 ) systemReportPrice FROM (select t1.id, t1.name, t1.code from test_team t1 where t1.pid = #{teamId}) t3 left join ( SELECT t3.id teamId, t3.NAME teamName, t3.CODE teamCode, t3.pid, SUM( IFNULL( t2.discount, 1 ) * IFNULL( t4.unit_price, 0 ) *IFNULL( t4.times, 0 ) ) taskPrice FROM test_task t1 LEFT JOIN test_entrusted_info t2 ON t1.entrustment_id = t2.id LEFT JOIN test_team t3 ON t1.dept_id = t3.id LEFT JOIN test_entrusted_sample_checkitem_rel t4 ON t1.id = t4.task_id
t1.review_time is not null
and t3.NAME = #{taskSource}
and t3.pid = #{teamId}
and DATE_FORMAT(t1.review_time, '%Y-%m-%d')>= DATE_FORMAT(#{beginDate}, '%Y-%m-%d')
and DATE_FORMAT(t1.review_time, '%Y-%m-%d')<= DATE_FORMAT(#{endDate}, '%Y-%m-%d')
GROUP BY t3.NAME, t3.CODE, t3.id ) t1 on t3.id = t1.teamId LEFT JOIN ( SELECT t3.id teamId, t3.NAME teamName, SUM( IFNULL( t2.discount, 1 ) * IFNULL( t5.unit_price, 0 ) * IFNULL( t5.times, 0 ) ) actualReportPrice, SUM( IFNULL( t5.unit_price, 0 )) systemReportPrice FROM test_task t1 LEFT JOIN test_entrusted_info t2 ON t1.entrustment_id = t2.id LEFT JOIN test_team t3 ON t1.dept_id = t3.id LEFT JOIN test_report_record t4 ON t2.id = t4.entrustment_id LEFT JOIN test_entrusted_sample_checkitem_rel t5 ON t1.id = t5.task_id
and t3.NAME = #{taskSource}
and t3.pid = #{teamId}
and DATE_FORMAT(t4.issuer_time, '%Y-%m-%d')>= DATE_FORMAT(#{beginDate}, '%Y-%m-%d')
and DATE_FORMAT(t4.issuer_time, '%Y-%m-%d')<= DATE_FORMAT(#{endDate}, '%Y-%m-%d')
GROUP BY t3.NAME, t3.id ) t2 ON t3.id = t2.teamId

SELECT t3.id teamId, t3.name teamName, IFNULL(t3.code,'——') teamCode, IFNULL(t1.taskPrice,0) taskPrice, IFNULL( t2.actualReportPrice, 0 ) actualReportPrice, IFNULL( t2.systemReportPrice, 0 ) systemReportPrice FROM (select t1.id, t1.name, t1.code from (SELECT id, NAME, id AS pid, CODE FROM test_team UNION ALL SELECT old_team_id AS id, old_team_name AS NAME, new_team_id AS pid, old_team_code FROM test_team_rel ) t1 where t1.pid = #{teamId}) t3 left join ( SELECT t3.id teamId, t3.NAME teamName, t3.CODE teamCode, t3.pid, SUM( IFNULL( t2.discount, 1 ) * IFNULL( t4.unit_price, 0 ) *IFNULL( t4.times, 0 ) ) taskPrice FROM test_task t1 LEFT JOIN test_entrusted_info t2 ON t1.entrustment_id = t2.id LEFT JOIN ( SELECT id, NAME,id AS pid,CODE FROM test_team UNION ALL SELECT old_team_id AS id,old_team_name AS NAME,new_team_id AS pid,old_team_code AS CODE FROM test_team_rel ) t3 ON t1.dept_id = t3.id LEFT JOIN test_entrusted_sample_checkitem_rel t4 ON t1.id = t4.task_id
t1.review_time is not null
and t3.NAME = #{taskSource}
and t3.pid = #{teamId}
and DATE_FORMAT(t1.review_time, '%Y-%m-%d')>= DATE_FORMAT(#{beginDate}, '%Y-%m-%d')
and DATE_FORMAT(t1.review_time, '%Y-%m-%d')<= DATE_FORMAT(#{endDate}, '%Y-%m-%d')
GROUP BY t3.NAME, t3.CODE, t3.id ) t1 on t3.id = t1.teamId LEFT JOIN ( SELECT t3.id teamId, t3.NAME teamName, SUM( IFNULL( t2.discount, 1 ) * IFNULL( t5.unit_price, 0 ) * IFNULL( t5.times, 0 ) ) actualReportPrice, SUM( IFNULL( t5.unit_price, 0 )) * 1.00 systemReportPrice FROM test_task_statistics t1 LEFT JOIN test_entrusted_info t2 ON t1.entrustment_id = t2.id LEFT JOIN ( SELECT id, NAME,id AS pid,CODE FROM test_team UNION ALL SELECT old_team_id AS id,old_team_name AS NAME,new_team_id AS pid,old_team_code AS CODE FROM test_team_rel ) t3 ON t1.dept_id = t3.id LEFT JOIN test_entrusted_sample_checkitem_statistics t5 ON t1.id = t5.task_id AND DATE_FORMAT( t1.issuer_time, '%Y-%m-%d' ) = DATE_FORMAT( t5.issuer_time, '%Y-%m-%d' )
and t3.NAME = #{taskSource}
and t3.pid = #{teamId}
and DATE_FORMAT(t1.issuer_time, '%Y-%m-%d')>= DATE_FORMAT(#{beginDate}, '%Y-%m-%d')
and DATE_FORMAT(t1.issuer_time, '%Y-%m-%d')<= DATE_FORMAT(#{endDate}, '%Y-%m-%d')
GROUP BY t3.NAME, t3.id ) t2 ON t3.id = t2.teamId

SELECT id, inspector inspector, reviewer reviewer, orderer, entrustment_id as entrustmentId FROM test_task where 1=1
and create_time >= #{startDate}
and create_time <= #{stopDate}
GROUP BY(CONCAT(orderer,entrustment_id))

SELECT business_acceptor AS businessAcceptor, COUNT( business_acceptor ) AS count FROM test_entrusted_info WHERE 1 = 1
AND business_acceptor IN
#{name}
and acceptance_date >= #{startDate}
and acceptance_date <= #{stopDate}
GROUP BY business_acceptor

SELECT tt.orderer as orderer, COUNT( tt.orderer ) AS count FROM ( SELECT orderer,create_time FROM test_task GROUP BY ( CONCAT( orderer, entrustment_id ) ) ) AS tt WHERE 1 = 1
and tt.orderer IN
#{name}
and tt.create_time >= #{startDate}
and tt.create_time <= #{stopDate}
GROUP BY tt.orderer

select.foreach:
SELECT #{keyword} AS inspector, COUNT(*) AS count
FROM test_task
WHERE inspector LIKE CONCAT('%', #{keyword}, '%')

    and start_detection_time  >=   #{startDate}


    and end_detection_time  <=   #{stopDate}

SELECT #{keyword} AS reviewer, COUNT(*) AS count
FROM test_task
WHERE reviewer LIKE CONCAT('%', #{keyword}, '%')

    and review_time  >=   #{startDate}


    and review_time  <=   #{stopDate}

mapper.select:
SELECT verifyer_id as verifyerId, COUNT( verifyer_id ) AS count FROM test_report_record WHERE 1 = 1
and verifyer_id IN
#{name}
and verifyer_time >= #{startDate}
and verifyer_time <= #{stopDate}
GROUP BY verifyer_id

SELECT issuer_id issuerId, COUNT( issuer_id ) AS count FROM test_report_record WHERE 1 = 1
and issuer_id IN
#{name}
and issuer_time >= #{startDate}
and issuer_time <= #{stopDate}
GROUP BY issuer_id

