SELECT #{keyword} as sealer, COUNT(*) AS count FROM test_report_record WHERE sealer LIKE CONCAT('%', #{keyword}, '%')
and seal_time >= #{startDate}
and seal_time <= #{stopDate}

SELECT #{keyword} AS reportProducer, COUNT(*) AS count
FROM test_task
